const itemsPerPage = 15;
let currentPage = 1;

function renderTable() {
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentData = data.slice(startIndex, endIndex);

  table.innerHTML = '';
  const thead = document.createElement('thead');
  const headerRow = document.createElement('tr');
  const headers = ['id','x(m)','y(m)','z(m)','distance(m)', 'Capacity(MB/s)', 'average arrival time(s)', 'Interference(dB)', 'Noise(dB)', 'SNR', 'SIR', 'SINR', 'Environment', 'Base station type', 'Base station ID', 'Base station coordinates', 'Total Capacity', 'total bandwidth(GHZ)', 'Number of interfaces', 'Delay(ms)'];
  headers.forEach(headerText => {
    const th = document.createElement('th');
    th.textContent = headerText;
    headerRow.appendChild(th);
  });
  thead.appendChild(headerRow);
  table.appendChild(thead);
  const tbody = document.createElement('tbody');
  currentData.forEach(item => {
    const row = document.createElement('tr');
    // 按照实际的数据属性渲染单元格
    headers.forEach(header => {
      const cell = document.createElement('td');
      cell.textContent = item[header];
      row.appendChild(cell);
    });
    tbody.appendChild(row);
  });
  table.appendChild(tbody);
}


function renderPagination() {
  const totalPages = Math.ceil(data.length / itemsPerPage);
  pagination.innerHTML = '';

  for (let i = 1; i <= totalPages; i++) {
    const button = document.createElement('button');
    button.textContent = i;
    button.addEventListener('click', () => {
      currentPage = i;
      renderTable();
      renderPagination();
    });
    if (i === currentPage) {
      button.disabled = true;
    }
    pagination.appendChild(button);
  }
}

renderTable();
renderPagination();

// 按钮4：下载文件
const downloadButton = document.getElementById('download-button');
downloadButton.addEventListener('click', () => {
  const link = document.createElement('a');
  link.href = 'sampled_data.csv';
  link.download = 'sampled_data.csv';
  link.click();
});

